'use client'
import { cn, getLinkComponent, useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import {
  Fragment,
  useId,
  type CSSProperties,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  type RefObject,
} from 'react'
import { Tooltip } from '../tooltip/tooltip'
import { usePopover } from '../popover/use-popover'
import styles from './side-nav.module.css'

export type SideNavTone = 'default' | 'danger' | 'warning' | 'success'

/**
 * The anchor props cascivo computes for a nav item — the exact bag it spreads onto
 * the link element. Passed to a `render` hatch so a custom link (e.g. a router
 * `<Link>`) can carry the same active-state and accessibility attributes.
 */
export interface SideNavLinkProps {
  href?: string | undefined
  className?: string | undefined
  'aria-current'?: 'page' | undefined
  'aria-label'?: string | undefined
  'aria-disabled'?: boolean | undefined
  'data-state'?: 'active' | undefined
  'data-tone'?: Exclude<SideNavTone, 'default'> | undefined
  tabIndex?: number | undefined
  onClick: (e: MouseEvent<HTMLAnchorElement>) => void
}

/** A selectable/navigable sub-item (link when `href` is set, action when `onSelect` is set). */
export interface SideNavLinkSubItem {
  /** Stable React key. Provide when `label`/`href` may repeat (e.g. placeholder `#` links). */
  id?: string
  label: string
  href?: string
  icon?: ReactNode
  active?: boolean
  /** Shows a trailing checkmark; use for picker-style "current selection" rows. */
  selected?: boolean
  /** Runs an action instead of navigating. When set without `href`, renders a `<button>`. */
  onSelect?: () => void
  disabled?: boolean
}

export type SideNavSubItem =
  | SideNavLinkSubItem
  | { type: 'separator' }
  | { type: 'label'; label: string }

export interface SideNavItem {
  /** Stable React key. Provide when `label`/`href` may repeat (e.g. placeholder `#` links). */
  id?: string
  label: string
  href?: string
  icon?: ReactNode
  active?: boolean
  items?: SideNavSubItem[]
  onClick?: (e: MouseEvent<HTMLAnchorElement>) => void
  /** Non-interactive and visually dimmed. */
  disabled?: boolean
  /** Recolors the item; `'default'` is the standard subtle color. */
  tone?: SideNavTone
  /** Rendered right-aligned after the label (e.g. a Kbd hint, badge, count); hidden on the rail. */
  trailing?: ReactNode
  /**
   * Escape hatch: render arbitrary content inside the item's shell so it inherits
   * alignment and the collapse context. When set, the item's own fields are ignored.
   *
   * `children` is the computed icon + label + trailing node (so a custom link keeps
   * the default layout), and `linkProps` is the anchor prop bag cascivo would spread
   * onto the `<a>` (including active-state and a11y attributes) — spread it onto your
   * router `<Link>` to preserve them. For a global router integration prefer
   * `setLinkComponent` from `@cascivo/core` over a per-item hatch.
   */
  render?: (ctx: {
    collapsed: boolean
    children: ReactNode
    linkProps: SideNavLinkProps
  }) => ReactNode
}

export interface SideNavGroup {
  label?: string
  items: SideNavItem[]
}

export interface SideNavProps {
  items?: SideNavItem[]
  groups?: SideNavGroup[]
  collapsed?: boolean
  defaultCollapsed?: boolean
  onCollapsedChange?: (collapsed: boolean) => void
  ariaLabel?: string
  collapseLabel?: string
  expandLabel?: string
  expandOnHover?: boolean
  showCollapseToggle?: boolean
  /** Content rendered above the items, inside the item padding context. */
  header?: ReactNode
  footer?: ReactNode
  className?: string
}

function isLinkSubItem(sub: SideNavSubItem): sub is SideNavLinkSubItem {
  return !('type' in sub)
}

function CheckMark() {
  return (
    <svg
      viewBox="0 0 16 16"
      width="14"
      height="14"
      aria-hidden="true"
      className={styles['checkMark']}
    >
      <path
        d="M3.5 8.5l3 3 6-7"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

interface SubControlOptions {
  inMenu: boolean
  onActivate?: () => void
  extraClass?: string | undefined
}

/** Renders the interactive control for a link/action sub-item (shared by inline + flyout). */
function renderSubControl(
  sub: SideNavLinkSubItem,
  { inMenu, onActivate, extraClass }: SubControlOptions,
) {
  const role = inMenu ? 'menuitem' : undefined
  const className = cn(styles['link'], styles['sublink'], extraClass)
  const inner = (
    <>
      {sub.icon ? (
        <span className={styles['icon']} aria-hidden="true">
          {sub.icon}
        </span>
      ) : null}
      <span className={styles['label']}>{sub.label}</span>
      {sub.selected ? <CheckMark /> : null}
    </>
  )

  if (sub.onSelect && !sub.href) {
    return (
      <button
        type="button"
        role={role}
        aria-current={sub.active ? 'page' : undefined}
        data-state={sub.active ? 'active' : undefined}
        data-selected={sub.selected || undefined}
        disabled={sub.disabled}
        className={className}
        onClick={() => {
          sub.onSelect?.()
          onActivate?.()
        }}
      >
        {inner}
      </button>
    )
  }

  const LinkComponent = getLinkComponent()
  return (
    <LinkComponent
      href={sub.disabled ? undefined : sub.href}
      role={role}
      aria-current={sub.active ? 'page' : undefined}
      aria-disabled={sub.disabled || undefined}
      tabIndex={sub.disabled ? -1 : undefined}
      data-state={sub.active ? 'active' : undefined}
      data-selected={sub.selected || undefined}
      className={className}
      onClick={(e: MouseEvent<HTMLAnchorElement>) => {
        if (sub.disabled) {
          e.preventDefault()
          return
        }
        sub.onSelect?.()
        onActivate?.()
      }}
    >
      {inner}
    </LinkComponent>
  )
}

function firstGrapheme(label: string): string {
  if (typeof Intl !== 'undefined' && 'Segmenter' in Intl) {
    const seg = new Intl.Segmenter(undefined, { granularity: 'grapheme' })
    for (const s of seg.segment(label)) return s.segment
  }
  return [...label][0] ?? ''
}

interface RailGroupFlyoutProps {
  item: SideNavItem & { items: SideNavSubItem[] }
}

function RailGroupFlyout({ item }: RailGroupFlyoutProps) {
  const { triggerRef, popoverRef, isOpen, anchorName, open, close, toggle } = usePopover()

  const menuItemSelector = '[role="menuitem"]:not([disabled]):not([aria-disabled="true"])'

  const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      if (!isOpen.value) open()
      const panel = popoverRef.current
      if (panel) {
        setTimeout(() => {
          panel.querySelector<HTMLElement>(menuItemSelector)?.focus()
        }, 0)
      }
    } else if (e.key === 'Escape') {
      close()
    }
  }

  const handlePanelKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    const panel = popoverRef.current
    if (!panel) return
    const items = Array.from(panel.querySelectorAll<HTMLElement>(menuItemSelector))
    const idx = items.indexOf(e.target as HTMLElement)
    if (e.key === 'ArrowDown') {
      e.preventDefault()
      items[(idx + 1) % items.length]?.focus()
    } else if (e.key === 'ArrowUp') {
      e.preventDefault()
      items[(idx - 1 + items.length) % items.length]?.focus()
    } else if (e.key === 'Escape') {
      e.preventDefault()
      close()
      triggerRef.current?.focus()
    }
  }

  return (
    <>
      <button
        ref={triggerRef as RefObject<HTMLButtonElement>}
        type="button"
        aria-haspopup="menu"
        aria-expanded={isOpen.value}
        aria-label={item.label}
        data-state={isOpen.value ? 'open' : 'closed'}
        style={{ anchorName } as CSSProperties}
        className={styles['groupTrigger']}
        onClick={() => toggle()}
        onKeyDown={handleKeyDown}
      >
        {item.icon ? (
          <span className={styles['icon']} aria-hidden="true">
            {item.icon}
          </span>
        ) : (
          <span className={styles['fallbackIcon']} data-fallback-icon aria-hidden="true">
            {firstGrapheme(item.label)}
          </span>
        )}
      </button>
      <div
        ref={popoverRef as RefObject<HTMLDivElement>}
        popover="auto"
        role="menu"
        aria-label={item.label}
        style={{ positionAnchor: anchorName } as CSSProperties}
        className={styles['railFlyout']}
        onKeyDown={handlePanelKeyDown}
      >
        <div className={styles['railFlyoutCaption']} aria-hidden="true">
          {item.label}
        </div>
        {item.items.map((sub, si) => {
          if (!isLinkSubItem(sub)) {
            return sub.type === 'separator' ? (
              <div key={si} role="separator" className={styles['flyoutSeparator']} />
            ) : (
              <div key={si} className={styles['railFlyoutCaption']} aria-hidden="true">
                {sub.label}
              </div>
            )
          }
          return (
            <Fragment key={si}>
              {renderSubControl(sub, {
                inMenu: true,
                onActivate: close,
                extraClass: styles['flyoutItem'],
              })}
            </Fragment>
          )
        })}
      </div>
    </>
  )
}

export function SideNav({
  items,
  groups,
  collapsed,
  defaultCollapsed = false,
  onCollapsedChange,
  ariaLabel,
  collapseLabel,
  expandLabel,
  expandOnHover = false,
  showCollapseToggle = true,
  header,
  footer,
  className,
}: SideNavProps) {
  useSignals()
  const resolvedAriaLabel = ariaLabel ?? t(builtin.sideNav.nav)
  const resolvedCollapseLabel = collapseLabel ?? t(builtin.sideNav.collapse)
  const resolvedExpandLabel = expandLabel ?? t(builtin.sideNav.expand)
  const baseId = useId()

  const isCollapsed = useSignal(collapsed ?? defaultCollapsed)
  if (collapsed !== undefined) isCollapsed.value = collapsed

  const effectiveGroups: SideNavGroup[] = groups ?? (items ? [{ items }] : [{ items: [] }])

  const allItems = effectiveGroups.flatMap((g) => g.items)
  const expandedGroups = useSignal<string[]>(
    allItems
      .filter((item) => item.items?.some((sub) => isLinkSubItem(sub) && sub.active))
      .map((item) => item.label),
  )

  const toggleGroup = (label: string) => {
    const current = expandedGroups.value
    expandedGroups.value = current.includes(label)
      ? current.filter((l) => l !== label)
      : [...current, label]
  }

  const toggleCollapsed = () => {
    const next = !isCollapsed.value
    if (collapsed === undefined) isCollapsed.value = next
    onCollapsedChange?.(next)
  }

  const rail = isCollapsed.value

  return (
    <nav
      aria-label={resolvedAriaLabel}
      data-state={rail ? 'collapsed' : 'expanded'}
      data-expand-on-hover={rail && expandOnHover ? '' : undefined}
      className={cn(styles['sideNav'], className)}
    >
      {header && <div className={styles['header']}>{header}</div>}
      <ul className={styles['list']}>
        {effectiveGroups.map((group, gi) => (
          <li key={gi} className={styles['group']}>
            {group.label && <h3 className={styles['groupLabel']}>{group.label}</h3>}
            <ul className={styles['groupItems']}>
              {group.items.map((item, index) => {
                const globalIndex = `${gi}-${index}`
                if (item.items) {
                  if (rail && !expandOnHover) {
                    return (
                      <li key={item.id ?? globalIndex}>
                        <RailGroupFlyout item={item as SideNavItem & { items: SideNavSubItem[] }} />
                      </li>
                    )
                  }
                  const open = expandedGroups.value.includes(item.label)
                  const sublistId = `${baseId}-group-${globalIndex}`
                  return (
                    <li key={item.id ?? globalIndex}>
                      <button
                        type="button"
                        aria-expanded={open}
                        aria-controls={sublistId}
                        aria-label={rail ? item.label : undefined}
                        data-state={open ? 'open' : 'closed'}
                        className={styles['groupTrigger']}
                        onClick={() => toggleGroup(item.label)}
                      >
                        {item.icon ? (
                          <span className={styles['icon']} aria-hidden="true">
                            {item.icon}
                          </span>
                        ) : rail ? (
                          <span
                            className={styles['fallbackIcon']}
                            data-fallback-icon
                            aria-hidden="true"
                          >
                            {firstGrapheme(item.label)}
                          </span>
                        ) : null}
                        <span className={styles['label']} data-rail-hidden={rail || undefined}>
                          {item.label}
                        </span>
                        <svg
                          viewBox="0 0 16 16"
                          width="12"
                          height="12"
                          aria-hidden="true"
                          className={styles['groupIndicator']}
                        >
                          <path
                            d="M4 6l4 4 4-4"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="1.5"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                          />
                        </svg>
                      </button>
                      <div
                        id={sublistId}
                        data-state={open ? 'open' : 'closed'}
                        className={styles['sublist']}
                      >
                        <ul className={styles['sublistInner']}>
                          {item.items.map((sub, si) => {
                            if (!isLinkSubItem(sub)) {
                              return sub.type === 'separator' ? (
                                <li key={si} role="separator" className={styles['subSeparator']} />
                              ) : (
                                <li key={si} className={styles['subGroupLabel']}>
                                  {sub.label}
                                </li>
                              )
                            }
                            return <li key={si}>{renderSubControl(sub, { inMenu: false })}</li>
                          })}
                        </ul>
                      </div>
                    </li>
                  )
                }

                const inner = (
                  <>
                    {item.icon ? (
                      <span className={styles['icon']} aria-hidden="true">
                        {item.icon}
                      </span>
                    ) : rail ? (
                      <span
                        className={styles['fallbackIcon']}
                        data-fallback-icon
                        aria-hidden="true"
                      >
                        {firstGrapheme(item.label)}
                      </span>
                    ) : null}
                    <span className={styles['label']} data-rail-hidden={rail || undefined}>
                      {item.label}
                    </span>
                    {item.trailing != null ? (
                      <span className={styles['trailing']} data-rail-hidden={rail || undefined}>
                        {item.trailing}
                      </span>
                    ) : null}
                  </>
                )

                const tone = item.tone && item.tone !== 'default' ? item.tone : undefined
                const linkProps: SideNavLinkProps = {
                  href: item.disabled ? undefined : item.href,
                  'aria-current': item.active ? 'page' : undefined,
                  'aria-label': rail ? item.label : undefined,
                  'aria-disabled': item.disabled || undefined,
                  tabIndex: item.disabled ? -1 : undefined,
                  'data-state': item.active ? 'active' : undefined,
                  'data-tone': tone,
                  className: styles['link'],
                  onClick: (e) => {
                    if (item.disabled) {
                      e.preventDefault()
                      return
                    }
                    item.onClick?.(e)
                  },
                }

                if (item.render) {
                  return (
                    <li key={item.id ?? globalIndex} className={styles['customItem']}>
                      {item.render({ collapsed: rail, children: inner, linkProps })}
                    </li>
                  )
                }

                // Renders through the app-registered link component (see
                // `setLinkComponent`), defaulting to a plain `<a>`. Passing the full
                // computed prop bag keeps active-state (`aria-current`/`data-state`)
                // and layout intact for a router `<Link>`.
                const LinkComponent = getLinkComponent()
                const link =
                  item.onClick && !item.href ? (
                    <button
                      type="button"
                      aria-current={item.active ? 'page' : undefined}
                      aria-label={rail ? item.label : undefined}
                      data-state={item.active ? 'active' : undefined}
                      data-tone={tone}
                      className={styles['link']}
                      disabled={item.disabled}
                      onClick={(e) => item.onClick?.(e as unknown as MouseEvent<HTMLAnchorElement>)}
                    >
                      {inner}
                    </button>
                  ) : (
                    <LinkComponent {...linkProps}>{inner}</LinkComponent>
                  )

                return (
                  <li key={item.id ?? globalIndex}>
                    {rail && !expandOnHover ? (
                      <Tooltip content={item.label} placement="right">
                        {link}
                      </Tooltip>
                    ) : (
                      link
                    )}
                  </li>
                )
              })}
            </ul>
          </li>
        ))}
      </ul>
      {footer && <div className={styles['footer']}>{footer}</div>}
      {showCollapseToggle && (
        <button
          type="button"
          aria-label={rail ? resolvedExpandLabel : resolvedCollapseLabel}
          className={styles['collapseToggle']}
          onClick={toggleCollapsed}
        >
          <svg
            viewBox="0 0 16 16"
            width="14"
            height="14"
            aria-hidden="true"
            className={styles['collapseIcon']}
          >
            <path
              d="M10 4l-4 4 4 4"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>
      )}
    </nav>
  )
}

@layer cascivo.component {
  .sideNav {
    box-sizing: border-box;
    display: flex;
    flex-direction: column;
    inline-size: var(--cascivo-sidenav-inline-size, 16rem);
    /* Fill a height-constrained parent and cap at it so the internal
       overflow:hidden auto below actually fires — a long nav scrolls inside the
       rail instead of growing past the parent and hiding its bottom entries.
       Was min-block-size:100% (#11), a *min* that defeats the internal scroll. */
    block-size: 100%;
    max-block-size: 100%;
    padding: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    background-color: var(--cascivo-sidenav-bg, var(--cascivo-color-surface));
    border-inline-end: 1px solid var(--cascivo-color-border);
    overflow-x: hidden;
    overflow-y: auto;
    transition: inline-size var(--cascivo-motion-emphasis);

    &[data-state='collapsed'] {
      inline-size: var(--cascivo-sidenav-rail-inline-size, 4rem);

      & .label[data-rail-hidden],
      & .trailing[data-rail-hidden] {
        display: none;
      }

      & .groupIndicator {
        display: none;
      }
    }

    &[data-expand-on-hover][data-state='collapsed'] {
      position: relative;

      &:hover,
      &:focus-within {
        inline-size: var(--cascivo-sidenav-inline-size, 16rem);
        position: absolute;
        inset-block: 0;
        z-index: 10;
        box-shadow: var(--cascivo-shadow-md);

        & .label[data-rail-hidden],
        & .trailing[data-rail-hidden] {
          display: initial;
        }

        & .link,
        & .groupTrigger {
          justify-content: flex-start;
          padding-inline: var(--cascivo-space-3);
        }

        & .groupIndicator {
          display: initial;
        }

        & .fallbackIcon {
          display: none;
        }
      }
    }
  }

  .list,
  .sublistInner,
  .groupItems {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    margin: 0;
    padding: 0;
    padding-inline: var(--cascivo-space-2);
    list-style: none;
  }

  .group {
    display: contents;
  }

  /* Visual separator between consecutive groups */
  .group + .group > .groupLabel,
  .group + .group > .groupItems:first-child {
    margin-block-start: var(--cascivo-space-4);
    padding-block-start: var(--cascivo-space-3);
    border-block-start: 1px solid var(--cascivo-color-border);
  }

  .groupLabel {
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2) var(--cascivo-space-1);
    font-size: var(--cascivo-text-xs);
    font-weight: 600;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--cascivo-color-foreground-muted);
    margin: 0;
  }

  .link,
  .groupTrigger {
    position: relative;
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-2);
    inline-size: 100%;
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-2);
    font-family: inherit;
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-tight);
    text-align: start;
    text-decoration: none;
    white-space: nowrap;
    color: var(--cascivo-color-text-subtle);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-item);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .link[data-state='active'] {
    color: var(--cascivo-color-text);
    font-weight: var(--cascivo-font-medium);
    background-color: var(--cascivo-color-accent-subtle);

    &::before {
      content: '';
      position: absolute;
      inset-block: var(--cascivo-radius-item);
      inset-inline-start: 0;
      inline-size: 2px;
      background: var(--cascivo-color-accent);
      border-radius: var(--cascivo-radius-full);
    }
  }

  /* Tone — recolors action items (e.g. reconnect = warning) */
  .link[data-tone='danger'] {
    color: var(--cascivo-color-destructive);
  }

  .link[data-tone='warning'] {
    color: var(--cascivo-color-warning);
  }

  .link[data-tone='success'] {
    color: var(--cascivo-color-success);
  }

  /* Disabled — non-interactive and dimmed (button uses :disabled, anchor uses aria-disabled) */
  .link:disabled,
  .link[aria-disabled='true'] {
    opacity: 0.5;
    cursor: not-allowed;
    pointer-events: none;
  }

  /* Trailing slot — right-aligned hint/badge after the label */
  .trailing {
    display: inline-flex;
    align-items: center;
    flex-shrink: 0;
    margin-inline-start: auto;
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-subtle);
  }

  /* Selected checkmark on picker-style sub-items */
  .checkMark {
    flex-shrink: 0;
    margin-inline-start: auto;
    color: var(--cascivo-color-accent);
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    inline-size: var(--cascivo-space-4);
    block-size: var(--cascivo-space-4);
  }

  .fallbackIcon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    inline-size: 1.25rem;
    block-size: 1.25rem;
    border-radius: 50%;
    background: var(--cascivo-color-bg-subtle);
    font-size: 0.6875rem;
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
  }

  .label {
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .groupIndicator {
    flex-shrink: 0;
    margin-inline-start: auto;
    transition: rotate var(--cascivo-motion-emphasis);

    .groupTrigger[data-state='open'] & {
      rotate: 180deg;
    }
  }

  .sublist {
    display: grid;
    grid-template-rows: 0fr;
    visibility: hidden;
    transition:
      grid-template-rows var(--cascivo-motion-exit),
      visibility var(--cascivo-motion-exit);

    &[data-state='open'] {
      grid-template-rows: 1fr;
      visibility: visible;
      transition:
        grid-template-rows var(--cascivo-motion-enter),
        visibility var(--cascivo-motion-enter);
    }
  }

  .sublistInner {
    min-block-size: 0;
    overflow: hidden;
  }

  .sublink {
    padding-inline-start: calc(
      var(--cascivo-space-3) + var(--cascivo-space-4) + var(--cascivo-space-2)
    );
  }

  .sublink[data-selected] {
    color: var(--cascivo-color-text);
    font-weight: var(--cascivo-font-medium);
  }

  /* Separator + section label inside an expandable item's inline sublist */
  .subSeparator {
    block-size: 1px;
    margin-block: var(--cascivo-space-1);
    margin-inline: var(--cascivo-space-3);
    background: var(--cascivo-color-border);
  }

  .subGroupLabel {
    padding-inline-start: calc(
      var(--cascivo-space-3) + var(--cascivo-space-4) + var(--cascivo-space-2)
    );
    padding-block: var(--cascivo-space-1);
    font-size: var(--cascivo-text-xs);
    font-weight: var(--cascivo-font-semibold);
    letter-spacing: 0.05em;
    text-transform: uppercase;
    color: var(--cascivo-color-text-subtle);
  }

  .header {
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  .footer {
    padding-block: var(--cascivo-space-2);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  /* Custom-item escape hatch — provides the item's padding/alignment context */
  .customItem {
    padding-block: var(--cascivo-space-2);
    padding-inline: var(--cascivo-space-2);
  }

  .collapseToggle {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-block-start: auto;
    padding-block: var(--cascivo-space-2);
    color: var(--cascivo-color-text-subtle);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .collapseIcon {
    transition: rotate var(--cascivo-motion-emphasis);

    .sideNav[data-state='collapsed'] & {
      rotate: 180deg;
    }
  }

  /* Rail flyout — anchored popover for group items in collapsed mode */
  .railFlyout {
    position: absolute;
    inset-block-start: anchor(start);
    inset-inline-start: anchor(end);
    margin: 0;
    min-inline-size: 11rem;
    padding: var(--cascivo-space-1);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    &:popover-open {
      display: flex;
      flex-direction: column;
      gap: 2px;
    }

    @starting-style {
      &:popover-open {
        opacity: 0;
        translate: -4px 0;
      }
    }

    transition:
      opacity var(--cascivo-duration-150) var(--cascivo-ease-out),
      translate var(--cascivo-duration-150) var(--cascivo-ease-out),
      display var(--cascivo-duration-150) var(--cascivo-ease-out) allow-discrete,
      overlay var(--cascivo-duration-150) var(--cascivo-ease-out) allow-discrete;
  }

  .railFlyoutCaption {
    padding-block: var(--cascivo-space-1);
    padding-inline: var(--cascivo-space-3);
    font-size: var(--cascivo-text-xs);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text-subtle);
    text-transform: uppercase;
    letter-spacing: 0.05em;
  }

  .flyoutItem {
    padding-inline-start: var(--cascivo-space-3);
    border-inline-start: none;
  }

  .flyoutSeparator {
    block-size: 1px;
    margin-block: var(--cascivo-space-1);
    margin-inline: var(--cascivo-space-2);
    background: var(--cascivo-color-border);
  }
}
